var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...큭.","JPN":"……くっ。","ENG":"...Kgh.","TWN":"……咳。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"울브즈베인이... 왜 갑자기 이렇게 무겁지?","JPN":"ウルブズベインが……急に重たくなった？","ENG":"Why does Wolvesbane... suddenly feel so heavy?","TWN":"狼之災禍……為什麼突然變得這麼沉重……？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L4_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이제 효과가 나타나기 시작한 모양이네요.","JPN":"そろそろ効果が出始めたようですね。","ENG":"It seems the effects are finally beginning to show.","TWN":"效果開始顯現了。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐...?","JPN":"何だって……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"운명을 끊어내는 흰 서리꽃이, 그 몸 안에서 늑대의 힘을 끊어내고 있어요.","JPN":"運命を断ち切る白い霜の花が、その体の中からオオカミの力を断ち切っているのです。","ENG":"The white frost flower that severs fate is cutting off the Wolf's power from within your body.","TWN":"斬斷命運的白霜花，正在切斷你體內狼的力量。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신은 이제 곧, 늑대가 아닌 평범한 인간이 되겠죠.","JPN":"あなたはもうすぐオオカミではない、普通の人間になるでしょう。","ENG":"Before long, you will become an ordinary human and no longer a Wolf.","TWN":"你很快就不再是狼，而只是普通的人類。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아무리 버티고 발버둥 쳐도 시간은 당신 편이 아니란 뜻이랍니다.","JPN":"どんなに耐えてあがいても、時間はあなたの味方ではないということです。","ENG":"No matter how much you endure and struggle, time is not on your side.","TWN":"無論你怎麼掙扎，時間都不站在你這邊。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"팔 하나를 잘라내면 다른 하나가 자라나. 이런 식으론 파고들 수 없겠어.","JPN":"腕を一本斬るともう一本が生えてくる。このままじゃ懐に入り込めない。","ENG":"If I cut off one arm, another one just grows right back. I can't break through like this.","TWN":"只要斬斷一隻手，另一隻就會再長出來。這樣無法突破。"},"stage":{"bg":"BLACK","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그렇다면...","JPN":"それなら……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"BLACK","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"레거시 디바이스 활성화.","JPN":"レガシーデバイス活性化。","ENG":"Legacy Device activated.","TWN":"啟動傳統設備。"},"stage":{"bg":"BLACK","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"울브즈베인, 바라밀 명도.","JPN":"ウルブズベイン、波羅蜜命刀。","ENG":"Wolvesbane, Sword of Paramita.","TWN":"狼之災禍，波羅蜜命刀。"},"stage":{"bg":"BLACK","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"윽...","JPN":"うっ……","ENG":"Ngh...","TWN":"唔……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"피하지 않고 과감하게 공격했지만, 정작 당신의 공격은 빗나갔네요.","JPN":"避けずに大胆な攻撃をしかけましたが、外れてしまいましたね。","ENG":"You attacked boldly without trying to evade, yet your strike missed.","TWN":"雖然沒有閃避果敢進攻，但你的攻擊落空了。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_WATER"},{"id":"L22_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"오른손이 움직이지 않는 게 느껴지나요? 희망은 잘려나간 힘줄을 대신해주지 않아요.","JPN":"右手が動かないのが分かりますか？　希望は斬られた筋肉の代わりにはなってくれません。","ENG":"Can you feel that your right hand won't move? Hope cannot replace severed tendons.","TWN":"感覺到右手無法動彈了嗎？希望無法取代被切斷的筋脈。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그런 말장난으론 아무것도 바꿀 수 없죠.","JPN":"こういう言葉遊びでは何も変えられないでしょう？","ENG":"Wordplay like that won't change anything.","TWN":"光靠那種話，無法改變任何事。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...그래. 희망이 내 손을 대신 움직여줄 순 없겠지.","JPN":"……そうだね。希望が右手を動かしてはくれることはないよね。","ENG":"...Right. Hope won't make my right hand move again.","TWN":"……是啊，希望無法讓我的右手動起來。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"공간이 무너지고 있어...?","JPN":"空間が崩れている……？","ENG":"Is the space collapsing...?","TWN":"空間在崩壞……？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그 사제는 어디로 사라졌지?!","JPN":"あの人はどこに消えちゃったの！？","ENG":"Where did he disappear to?!","TWN":"那個人去哪了？！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"...벨레스는 처음부터 없었어. 그건 거울에 비친 환영일 뿐이야.","JPN":"……ヴェレスは最初からいなかったよ。あれは反射した幻影だから。","ENG":"...Veles was never here to begin with. That was only a reflected illusion.","TWN":"……貝雷斯從一開始就不存在，那只是反射的幻影。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저건 나잖아? 이게 어떻게 된 거야?","JPN":"あれは私？　どうなってるの？","ENG":"That's me. What's going on?","TWN":"那不是我嗎？這到底怎麼回事？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"울브즈베인이. 선배가 그 남자의 거울을 부순 거야.","JPN":"ウルブズベインが。先輩があの男の鏡を壊したの。","ENG":"Wolvesbane. Mina destroyed that man's mirror.","TWN":"狼之災禍，是前輩擊碎了那男人的鏡子。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"그리고 나 역시, 그 남자가 너흴 가두기 위해 준비한 거울들 중 하나.","JPN":"そして私も、あの男があなたたちを閉じ込めるために用意した鏡の一つ。","ENG":"And I'm also one of the mirrors he prepared to trap you.","TWN":"而我，也是那男人用來困住你們的其中一面鏡子。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"그림자 전당에서 보았던 너 자신을 기억해?","JPN":"影の殿堂で見たあなた自身のことを覚えてる？","ENG":"Do you remember the version of yourself you saw in the Shadow Palaces?","TWN":"還記得你在暗影殿堂看到的自己嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"...아!","JPN":"……あ！","ENG":"...Ah!","TWN":"……啊！"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"여러분, 들리시나요?","JPN":"皆さん、聞こえますか？","ENG":"Can everyone hear me?","TWN":"各位，聽得到嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_83"},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"...이 목소리는?","JPN":"……この声は？","ENG":"...That voice...","TWN":"……這聲音是？"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"...노엘 양?","JPN":"……ノエルさん？","ENG":"...Noelle?","TWN":"……洛艾兒小姐？"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"저희가 있는 곳은 이면세계가 아녜요! 스완의 파노라마를 본 따 만들어진 거울 속 세계일 뿐이죠!","JPN":"私たちがいる場所は裏世界ではありません！　スワンのパノラマを真似て作られた、鏡の中の世界です！","ENG":"Where we are isn't the Counterside! It's just a world inside a mirror modeled after Swan's panorama!","TWN":"我們所在的地方並不是異界！只是模仿史旺的全景所構築的鏡中世界！"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_20"},{"id":"L46_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"파노라마라면...?","JPN":"パノラマって……？","ENG":"Panorama...?","TWN":"全景……？"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"과연, 그걸 미나 양이 깨부순 거로군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"자기 자신을 이겨야만 빠져나갈 수 있는 미궁에서, 벨레스란 자가 자신을 가림막으로 정답을 숨겨 놓으니 거울이 보이지 않던 거였어요.","JPN":"抜け出すためには自分自身に勝たねばならない迷宮で、ヴェレスという者が正解を隠していたから道が見えなかったわけですね。","ENG":"In a labyrinth you can only escape by overcoming yourself, Veles hid the answer by placing himself as a screen in front of it.","TWN":"這是一個必須戰勝自我才能逃脫的迷宮，貝雷斯利用自己作為遮蔽物隱藏了真正的解法，才會看不到出路。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_COLD_NULL_ON","text":{"KOREA":"지금쯤 타기리온은 늑대와 전면전을 벌이고 있겠죠.","JPN":"今頃タギリオンはオオカミと決戦中でしょう。","ENG":"By now, Thagirion must be fighting the Wolf head-on.","TWN":"現在塔基里翁應該正與狼展開正面對決。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HORIZON_COLD_NULL_ON","text":{"KOREA":"허를 찌른다면, 여기서 탈출하는 순간이 기회일 겁니다.","JPN":"隙をつくなら、ここを抜け出る瞬間がチャンスです。","ENG":"If we strike at an opening, the moment we escape from here will be our chance.","TWN":"若能抓住破綻，這就是逃脫的機會。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그거라면 저에게 계획이 있어요!","JPN":"それなら、私に考えがあります！","ENG":"I have a plan for that!","TWN":"這樣的話我有個計畫！"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"절 믿고, 타기리온의 발을 잠시만 묶어주세요!","JPN":"私を信じて、少しだけタギリオンの足を止めてください！","ENG":"Trust me, and hold Thagirion in place just for a moment!","TWN":"請相信我，暫時幫我拖住塔基里翁！"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_20"},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"거울을 가리던 가림막이 사라졌으니, 이제 벗어나는 방법은 단순하다.","JPN":"鏡を隠していたものは消えた。抜け出す方法は単純だ。","ENG":"Now that the screen covering the mirror is gone, the method of escape is simple.","TWN":"既然擋住鏡子的遮蔽消失，接下來就很簡單了。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"허나 과연 네가 날 정면으로 이길 수 있을까?","JPN":"だが、そなたが正面から戦って我に勝てると思うか？","ENG":"But can you truly defeat me head-on?","TWN":"但你能正面擊敗我嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"물론이옵니다.","JPN":"もちろんでございます。","ENG":"Most certainly.","TWN":"當然可以。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"제 힘의 근원은 믿음.","JPN":"わたくしの力の根源は信じる心。","ENG":"Faith is the source of my strength.","TWN":"我的力量源自信念。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"과거의 에클레시아는, 스스로를 믿고 있는 지금의 절 이길 수 없을 것입니다!","JPN":"自分自身を信じられず崩れたあなたは、今のわたくしに勝つことはできません！","ENG":"You, who collapsed because you could not believe in yourself, cannot defeat me as I am now!","TWN":"連自己都不相信的你，是無法戰勝現在的我的。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"...좋은 대답이구나.","JPN":"……いい答えだ。","ENG":"...A fine answer.","TWN":"……回答得很好。"},"stage":{"bg":"MIND","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"네가 원한다면, 넌 자유로워질 것이다, 에클레시아.","JPN":"お前が望むなら、お前は自由になれる。エクレシア。","ENG":"If that is what you wish, you will be free, Ecclesia.","TWN":"只要你願意，你就能獲得自由，艾可露西亞。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"영원이 걸리는 한이 있어도, 내가 널 운명으로부터 해방시켜줄 테니까.","JPN":"永遠の時間がかかるとしても、私が運命から解放してあげよう。","ENG":"Even if it takes eternity, I will free you from fate.","TWN":"就算付出永恆的代價，我也會讓你從命運中解放。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_QM","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"황금나무가 요정들에게 속삭였다.","JPN":"黄金の木が妖精たちに囁いた。","ENG":"The Golden Tree whispered to the fairies.","TWN":"黃金樹對精靈低語。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"너희와 인간의 피가 섞인 아이는 자신이 사랑한 인간들에게 가장 끔찍한 배반을 당할 것이다.","JPN":"お前たちと人間の血が混ざった子は、自身が愛した人間に最も悲惨な形で裏切られるだろう。","ENG":"The child born of fairy and human blood will suffer the most terrible betrayal from the humans she loved.","TWN":"你們與人類之血誕生的孩子，將會遭受被自己所愛的人類徹底背叛。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 너 역시, 배반 당한 아이의 손에 죽음을 맞으리라.","JPN":"そしてお前もまた、裏切られた子の手により死を迎えるだろう。","ENG":"And you as well shall meet your death at the hands of that betrayed child.","TWN":"而你，也將死於那個被背叛的孩子之手。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"인간의 아이를 가지다니.","JPN":"人間との間に子をもうけるだなんて。","ENG":"To bear a human child...","TWN":"竟然讓人類誕下孩子……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"기어코, 당신이 그 예언을 실현시키고 마는구나.","JPN":"とうとうアナタは、あの予言を実現させてしまったのね。","ENG":"In the end, you truly will bring that prophecy to pass.","TWN":"你終究還是要實現那個預言。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"우리는 황금나무가 속삭이는 것들을 예언이라 부르죠.","JPN":"私たちは黄金の木の囁きを予言と呼びます。","ENG":"We call the things the Golden Tree whispers prophecy.","TWN":"我們將那些黃金樹的低語稱為預言。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"...그래. 그 무엇도 예언으로부터 도망칠 수 없어. 우리가 무슨 수를 써도 예언은 결국 이루어지고 마는 거니까.","JPN":"……ええ。どんな存在も予言からは逃げられないわ。アタシたちが何をしても、予言は実現してしまうものだから。","ENG":"...Yes. Nothing can escape prophecy. No matter what we do, prophecy will always come to pass in the end.","TWN":"……沒錯。沒有人能逃離預言。無論我們做什麼，預言終將成真。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그래서 선택했을 뿐입니다.","JPN":"だから選んだだけです。","ENG":"So I made a choice.","TWN":"所以我只是選擇了—"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"내가 그 운명의 죄인이 되기로.","JPN":"自分がその運命の罪人になることを。","ENG":"To become the sinner of that fate myself.","TWN":"成為那命運的罪人。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"악마가 되어서도, 넌 그 뜻을 관철할 수 있을까?","JPN":"悪魔になっても、アナタはその意志を貫き通せるかしら？","ENG":"Even if you become a demon, will you still be able to carry out that will?","TWN":"即使成為惡魔，你也要貫徹那個意志嗎？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"영원히 그 아이의 곁에 머물며... 그녀가 겪는 고통을 눈 떼지 않고 지켜볼 겁니다.","JPN":"永遠にあの子のそばを守り……彼女が経験する苦痛をしかと見守ります。","ENG":"I will remain by her side forever... and watch the suffering she endures without ever turning my eyes away.","TWN":"我會永遠待在那個孩子身邊……注視她承受的一切痛苦。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"모든 것을 잃은 채, 악마로 전락하는 한이 있더라도.","JPN":"たとえすべてを失い、悪魔に身を落とすことになるとしても。","ENG":"Even if I lose everything and fall into becoming a demon.","TWN":"即使失去一切，墮落為惡魔也在所不惜。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"...미안하다, 아우드라.","JPN":"……すまない、アウドラ。","ENG":"...I'm sorry, Audra.","TWN":"……對不起，奧德拉。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이번에도... 널 구하지 못했구나.","JPN":"今回も……そなたを助けられなかった。","ENG":"Once again... I couldn't save you.","TWN":"這一次……我還是沒能救你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"갑옷에 유폐된 몸으로 발버둥치며, 너의 경멸 어린 기만에 농락 당할 뿐.","JPN":"鎧に幽閉された体であがき、そなたの軽蔑めいた欺瞞に翻弄されるのみ。","ENG":"Trapped within this armor, I can do nothing but struggle and be toyed with by your scornful deception.","TWN":"只能在被鎧甲囚禁的身軀中掙扎，任由你輕蔑欺瞞戲弄。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"하지만... 이것 하나만은 약속하마.","JPN":"だが……これだけは約束しよう。","ENG":"But... there is one thing I can promise you.","TWN":"但是……我只會向你承諾一件事。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네가 나의 실패에 질려 도망치는 한이 있더라도, 난 너를 포기하지 않을 것임을.","JPN":"そなたが我の失敗に嫌気がさし逃げたとしても、我はそなたを諦めない。","ENG":"Even if you grow weary of my failures and flee from me, I will never give up on you.","TWN":"即使你厭倦我的失敗而逃離，我也絕不會放棄你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이제 말해줘요, 삼하인.","JPN":"教えてください、サウィン。","ENG":"Now, tell me, Samhain.","TWN":"現在告訴我吧，薩溫。"},"stage":{"bg":"MS_1302","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"당신이 나에게서 원했던 건... 고작 내 영혼 하나가 아닌 거죠?","JPN":"あなたが私に求めていたのは……私の魂だけではない、そうでしょう？","ENG":"What you wanted from me... it wasn't just my soul, was it?","TWN":"你從我這裡想要的……不僅僅是我的靈魂吧？"},"stage":{"bg":"MS_1302","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"제가 원하는 건 당신이 모든 기억을 간직한 채, 계속해서 미래로 나아가는 겁니다.","JPN":"私の望みは、あなたがすべての記憶を持ったまま、更なる未来へ進むことです。","ENG":"What I want is for you to keep moving forward with all your memories.","TWN":"我希望你能保留所有的記憶，繼續向未來前進。"},"stage":{"bg":"MS_1302","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"저는 당신의 영혼을 차표 삼아 그 운명에 오른 승객일 뿐이죠.","JPN":"私はあなたの魂をチケットの代わりにして、運命に乗り込んだ乗客にすぎない。","ENG":"I am merely a passenger who boarded on your fate using your soul as a ticket.","TWN":"我只是以你的靈魂為車票，登上命運之旅的乘客而已。"},"stage":{"bg":"MS_1302","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"당신은... 정체가 뭐죠?","JPN":"あなたは……何者ですか？","ENG":"Who... are you?","TWN":"你…是誰？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"나도 한때는 여러 이름으로 불렸습니다. 이름은 존재와 그 가치를 대변해주니까요.","JPN":"私もかつては様々な呼び名がありました。名前とは存在とその価値を代弁してくれますから。","ENG":"I was once called by many names. A name reflects one's entity and worth.","TWN":"我曾有過許多名字，每個名字都代表著不同的意義與價值。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"하지만 보다 근원적인 것들을 바라볼 수 있게 된 뒤로는, 문명의 몰락과 함께 나 또한 그 모든 이름을 버렸습니다.","JPN":"しかし、より根源的なものを見分けられるようになった現在は、文明の没落とともに、私もすべての名を捨て去りました。","ENG":"However, after being enlightened to see the fundamentals of all things, I have chosen to renounce all my names with the fall of civilization.","TWN":"但當我能看到更根源的東西後，我便將名字隨著文明的衰落一併丟棄。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너... 목적이 뭐지?","JPN":"アナタ……目的は何？","ENG":"What... is your objective in all of this?","TWN":"你…目的是什麼？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"마왕이 인류를 멸망시키면, 그 영혼에 기생하는 너도 무사하지 못할 텐데?","JPN":"魔王が人類を滅亡させれば、その魂に寄生しているアナタも無事では済まない。","ENG":"If the Demon Lord annihilates all of humanity, you will not be safe either as you need souls to leech from.","TWN":"如果魔王滅絕人類，寄生在人類靈魂上的你也不會倖免吧？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"마왕의 존재는 종말 그 자체이자, 멈출 수 없는 흐름입니다.","JPN":"魔王の存在は終末そのまのであり、止められない流れです。","ENG":"The existence of the Demon Lord is the end itself. There is no stopping it.","TWN":"魔王的存在本身就是終結，是無法停止的洪流。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"저항하다 부서지기보다, 그 흐름에 몸을 맡기는 쪽을 택했을 뿐이죠.","JPN":"私は流れに逆らい壊されるより、身を任せる方を選んだまでですよ。","ENG":"So instead of resisting, I have chosen to surrender to the flow.","TWN":"我只是選擇了順應這股洪流，而不是在抵抗中破碎。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"영원에 걸쳐 인과를 쌓아 올린다.","JPN":"永遠をかけて因果を積み上げる。","ENG":"To accumulate causality across eternity.","TWN":"在永恆中累積因果。"},"stage":{"bg":"SKY","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"내가 내린 선택 앞에 후회하며 등 돌리지 않기 위해서.","JPN":"自分が下した選択に後悔して背を向けないために。","ENG":"So that I won't regret and turn away from the choice I made.","TWN":"為了不在我做出的選擇前後悔。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"비록 그 모든 과정이 예언대로 되더라도, 마지막만은 너의 뜻이 될 수 있도록.","JPN":"たとえそのすべての過程が予言通りだとしても、最後だけはお前の意志となるように。","ENG":"Even if every step follows the prophecy, at least the final outcome can be your will.","TWN":"即使所有過程都按預言進行，也必須由你來決定最後的結局。"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...음?","JPN":"……ん？","ENG":"...Hm?","TWN":"……嗯？"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_WIND"},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"타기리오오온...!!!","JPN":"タギリオン……！！！","ENG":"THAGIRIOOOON...!!!","TWN":"塔基里翁……！！！"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_MONSTER_FIRE_ENERGY_SMALL_02"}]`);export{e as default};